  icon?: React.ReactNode;
  link?: string;
  onClose?: () => void;
}

const FeatureUnlockCelebration: React.FC<FeatureUnlockCelebrationProps> = ({
  feature,
  description,
  icon,
  link,
  onClose
}) => {
  const [isVisible, setIsVisible] = useState(true);
  const [isAnimating, setIsAnimating] = useState(true);

