import { useState, useEffect, useCallback } from 'react';
import { useFamily } from '../contexts/FamilyContext';
import { logger } from '../lib/logger';

export interface JourneyStepStatus {
  step: number;
  completed: boolean;
  completedAt?: Date;
  visited: boolean;
  visitedAt?: Date;
}

export interface JourneyProgress {
  step1: JourneyStepStatus; // Join Platform
  step2: JourneyStepStatus; // Service Catalog
  step3: JourneyStepStatus; // Privacy Panda
  step4: JourneyStepStatus; // Advanced Features
  overallProgress: number; // 0-100
  nextRecommendedStep: number;
}

const STORAGE_KEY = 'pandagarde_journey_progress';

const getDefaultProgress = (): JourneyProgress => ({
  step1: { step: 1, completed: false, visited: false },
  step2: { step: 2, completed: false, visited: false },
  step3: { step: 3, completed: false, visited: false },
  step4: { step: 4, completed: false, visited: false },
  overallProgress: 0,
  nextRecommendedStep: 1,
});

const loadProgress = (): JourneyProgress => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      const parsed = JSON.parse(stored);
      // Convert date strings back to Date objects
      Object.keys(parsed).forEach(key => {
        if (key.startsWith('step') && parsed[key]) {
          if (parsed[key].completedAt) {
            parsed[key].completedAt = new Date(parsed[key].completedAt);
          }
          if (parsed[key].visitedAt) {
            parsed[key].visitedAt = new Date(parsed[key].visitedAt);
          }
        }
      });
      return parsed;
    }
  } catch (error) {
    logger.error('Error loading journey progress:', error);
  }
  return getDefaultProgress();
};

const saveProgress = (progress: JourneyProgress): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  } catch (error) {
    logger.error('Error saving journey progress:', error);
  }
};

export const useJourneyProgress = () => {
  const { currentFamily, familyMembers } = useFamily();
  const [progress, setProgress] = useState<JourneyProgress>(loadProgress);

  // Calculate overall progress
  const calculateProgress = useCallback((currentProgress: JourneyProgress): number => {
    const steps = [currentProgress.step1, currentProgress.step2, currentProgress.step3, currentProgress.step4];
    const completedCount = steps.filter(s => s.completed).length;
    return (completedCount / 4) * 100;
  }, []);

  // Determine next recommended step
  const getNextRecommendedStep = useCallback((currentProgress: JourneyProgress): number => {
    if (!currentProgress.step1.completed) {return 1;}
    if (!currentProgress.step2.completed) {return 2;}
    if (!currentProgress.step3.completed) {return 3;}
    if (!currentProgress.step4.completed) {return 4;}
    return 4; // All completed
  }, []);

  // Mark step as visited
  const markStepVisited = useCallback((step: number) => {
    setProgress(prev => {
      const updated = { ...prev };
      const stepKey = `step${step}` as keyof JourneyProgress;
      const stepStatus = updated[stepKey] as JourneyStepStatus;

      if (!stepStatus.visited) {
        stepStatus.visited = true;
        stepStatus.visitedAt = new Date();
        updated.overallProgress = calculateProgress(updated);
        updated.nextRecommendedStep = getNextRecommendedStep(updated);
        saveProgress(updated);
      }

      return updated;
    });
  }, [calculateProgress, getNextRecommendedStep]);

  // Mark step as completed
  const markStepCompleted = useCallback((step: number) => {
    setProgress(prev => {
      const updated = { ...prev };
      const stepKey = `step${step}` as keyof JourneyProgress;
      const stepStatus = updated[stepKey] as JourneyStepStatus;

      if (!stepStatus.completed) {
        stepStatus.completed = true;
        stepStatus.completedAt = new Date();
        stepStatus.visited = true;
        stepStatus.visitedAt = new Date();
        updated.overallProgress = calculateProgress(updated);
        updated.nextRecommendedStep = getNextRecommendedStep(updated);
        saveProgress(updated);
      }

      return updated;
    });
  }, [calculateProgress, getNextRecommendedStep]);

  // Check step completion based on actual state
  useEffect(() => {
    setProgress(prev => {
      const updated = { ...prev };
      let changed = false;

      // Step 1: Join Platform - completed if family exists
      if (currentFamily && !updated.step1.completed) {
        updated.step1.completed = true;
        updated.step1.completedAt = new Date();
        updated.step1.visited = true;
        updated.step1.visitedAt = new Date();
        changed = true;
      }

      // Step 2: Service Catalog - completed if services added
      const totalServices = familyMembers.reduce((count, member) => {
        const memberServices = (member as any).services || [];
        return count + memberServices.length;
      }, 0);

      if (totalServices >= 3 && !updated.step2.completed) {
        updated.step2.completed = true;
        updated.step2.completedAt = new Date();
        updated.step2.visited = true;
        updated.step2.visitedAt = new Date();
        changed = true;
      }

      // Step 3: Privacy Panda - mark as visited if user has accessed it
      // This would be tracked when user visits /privacy-panda
      // For now, we'll check localStorage for privacy panda activity
      const privacyPandaVisited = localStorage.getItem('pandagarde_privacy_panda_visited');
      if (privacyPandaVisited && !updated.step3.visited) {
        updated.step3.visited = true;
        updated.step3.visitedAt = new Date(privacyPandaVisited);
        changed = true;
      }

      // Step 4: Advanced Features - completed if user has accessed digital footprint
      const footprintVisited = localStorage.getItem('pandagarde_digital_footprint_visited');
      if (footprintVisited && totalServices >= 3 && !updated.step4.completed) {
        updated.step4.completed = true;
        updated.step4.completedAt = new Date(footprintVisited);
        updated.step4.visited = true;
        updated.step4.visitedAt = new Date(footprintVisited);
        changed = true;
      }

      if (changed) {
        updated.overallProgress = calculateProgress(updated);
        updated.nextRecommendedStep = getNextRecommendedStep(updated);
        saveProgress(updated);
      }

      return updated;
    });
  }, [currentFamily, familyMembers, calculateProgress, getNextRecommendedStep]);

  // Reset progress
  const resetProgress = useCallback(() => {
    const defaultProgress = getDefaultProgress();
    setProgress(defaultProgress);
    saveProgress(defaultProgress);
  }, []);

  return {
    progress,
    markStepVisited,
    markStepCompleted,
    resetProgress,
    isStepCompleted: (step: number) => {
      const stepKey = `step${step}` as keyof JourneyProgress;
      return (progress[stepKey] as JourneyStepStatus).completed;
    },
    isStepVisited: (step: number) => {
      const stepKey = `step${step}` as keyof JourneyProgress;
      return (progress[stepKey] as JourneyStepStatus).visited;
    },
  };
};

/**
 * COPPA Compliance Manager
 * Handles parental consent, data collection restrictions, and COPPA compliance
 * 
 * Note: This is a client-side implementation. For full COPPA compliance,
 * consider implementing server-side verification in production.
 */

import { encryptData, decryptData, generateUserPassword } from './encryption';
import { logger } from './logger';

export interface ParentalConsentRecord {
  childAge: number;
  parentEmail: string;
  consentToken: string;
  consentDate: string;
  ipAddress?: string;
  consentMethod: 'email' | 'parental-portal';
  verified: boolean;
  revoked?: boolean;
  revokedDate?: string;
}

export interface ConsentVerificationResult {
  valid: boolean;
  record?: ParentalConsentRecord;
  error?: string;
}

export class COPPAComplianceManager {
  private static readonly CONSENT_STORAGE_KEY = 'pandagarde_coppa_consents';
  private static readonly ZERO_DATA_FLAG = 'pandagarde_zero_data_mode';
  
  /**
   * Generate a unique consent token
   */
  private generateConsentToken(): string {
    const timestamp = Date.now();
    const random = Math.random().toString(36).substring(2, 15);
    return `coppa_${timestamp}_${random}`;
  }

  /**
   * Store consent record (encrypted)
   */
  private async storeConsentRecord(token: string, record: ParentalConsentRecord): Promise<void> {
    try {
      const allConsents = await this.getAllConsentRecords();
      allConsents[token] = record;
      
      // Encrypt before storing
      const userId = this.getCurrentUserId();
      const password = generateUserPassword(userId);
      const encrypted = await encryptData(allConsents, password);
      
      localStorage.setItem(COPPAComplianceManager.CONSENT_STORAGE_KEY, encrypted);
    } catch (error) {
      logger.error('Error storing consent record:', error);
      throw new Error('Failed to store consent record');
    }
  }

  /**
   * Get all consent records (decrypted)
   */
  private async getAllConsentRecords(): Promise<Record<string, ParentalConsentRecord>> {
    try {
      const stored = localStorage.getItem(COPPAComplianceManager.CONSENT_STORAGE_KEY);
      if (!stored) {return {};}
      
      const userId = this.getCurrentUserId();
      const password = generateUserPassword(userId);
      return await decryptData<Record<string, ParentalConsentRecord>>(stored, password);
    } catch (error) {
      logger.error('Error getting consent records:', error);
      return {};
    }
  }

  /**
   * Get a specific consent record
   */
  async getConsentRecord(token: string): Promise<ParentalConsentRecord | null> {
    const allConsents = await this.getAllConsentRecords();
    return allConsents[token] || null;
  }

  /**
   * Request parental consent via email
   */
  async requestParentalConsent(
    childAge: number,
    parentEmail: string
  ): Promise<{ success: boolean; consentToken: string; error?: string }> {
    try {
      // Validate email
      if (!this.isValidEmail(parentEmail)) {
        return { success: false, consentToken: '', error: 'Invalid email address' };
      }

      // Generate consent token
      const consentToken = this.generateConsentToken();
      
      // Create consent record
      const consentRecord: ParentalConsentRecord = {
        childAge,
        parentEmail,
        consentToken,
        consentDate: new Date().toISOString(),
        consentMethod: 'email',
        verified: false
      };
      
      // Store consent record
      await this.storeConsentRecord(consentToken, consentRecord);
      
      // Send consent email
      const emailSent = await this.sendConsentEmail(parentEmail, consentToken);
      
      if (!emailSent) {
        return { 
          success: false, 
          consentToken, 
          error: 'Failed to send consent email. Please try again.' 
        };
      }
      
      return { success: true, consentToken };
    } catch (error) {
      logger.error('Error requesting parental consent:', error);
      return { 
        success: false, 
        consentToken: '', 
        error: 'An error occurred while processing your request' 
      };
    }
  }

  /**
   * Send consent email using EmailJS or similar service
   * Note: Configure EmailJS service ID and template in environment variables
   */
  private async sendConsentEmail(parentEmail: string, consentToken: string): Promise<boolean> {
    try {
      // Check if EmailJS is configured
      const emailjsServiceId = import.meta.env['VITE_EMAILJS_SERVICE_ID'];
      const emailjsTemplateId = import.meta.env['VITE_EMAILJS_TEMPLATE_ID'];
      const emailjsPublicKey = import.meta.env['VITE_EMAILJS_PUBLIC_KEY'];

      if (!emailjsServiceId || !emailjsTemplateId || !emailjsPublicKey) {
        // Fallback: Use mailto link or log for manual processing
        logger.warn('EmailJS not configured. Consent token:', consentToken);
        logger.warn('Parent email:', parentEmail);
        logger.warn('Consent URL:', `${window.location.origin}/parental-consent?token=${consentToken}`);
        
        // In development, we'll simulate success
        // In production, you should configure EmailJS or another email service
        return true;
      }

      // Try to send email using EmailJS if available
      // Note: EmailJS is optional - install with: npm install @emailjs/browser
      const consentUrl = `${window.location.origin}/parental-consent?token=${consentToken}`;
      
      try {
        // Dynamic import of EmailJS (if installed)
        // @ts-expect-error - EmailJS is optional dependency
        const emailjsModule = await import('@emailjs/browser').catch(() => null);
        
        if (emailjsModule && emailjsServiceId && emailjsTemplateId && emailjsPublicKey) {
          const templateParams = {
            to_email: parentEmail,
            consent_token: consentToken,
            consent_url: consentUrl,
            site_name: 'PandaGarde',
            support_email: import.meta.env['VITE_SUPPORT_EMAIL'] || 'support@pandagarde.com'
          };

          // Add timeout for email sending
          const emailPromise = emailjsModule.send(
            emailjsServiceId,
            emailjsTemplateId,
            templateParams,
            emailjsPublicKey
          );
          
          const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error('Email send timeout')), 10000)
          );
          
          await Promise.race([emailPromise, timeoutPromise]);
          return true;
        }
      } catch (emailError) {
        // Silently fail - fallback to manual processing
        logger.warn('EmailJS error (falling back to manual processing):', emailError);
        // Fall through to manual processing
      }
      
      // Fallback: Log consent details for manual email sending
      // In production, you should configure EmailJS or another email service
      logger.warn('EmailJS not configured. Manual consent email required:');
      logger.warn('Parent Email:', parentEmail);
      logger.warn('Consent Token:', consentToken);
      logger.warn('Consent URL:', consentUrl);
      
      // In development, return true to allow testing
      // In production, you may want to return false and require email service
      return import.meta.env.MODE === 'development';
    } catch (error) {
      logger.error('Error sending consent email:', error);
      // Return true in development to allow testing
      // In production, you may want to return false
      return import.meta.env.MODE === 'development';
    }
  }

  /**
   * Verify consent token from email link
   */
  async verifyConsentToken(token: string): Promise<ConsentVerificationResult> {
    try {
      const record = await this.getConsentRecord(token);
      
      if (!record) {
        return { valid: false, error: 'Invalid consent token' };
      }

      if (record.revoked) {
        return { valid: false, error: 'This consent has been revoked' };
      }

      // Mark as verified
      record.verified = true;
      await this.storeConsentRecord(token, record);

      return { valid: true, record };
    } catch (error) {
      logger.error('Error verifying consent token:', error);
      return { valid: false, error: 'Failed to verify consent token' };
    }
  }

  /**
   * Revoke parental consent
   */
  async revokeConsent(token: string): Promise<boolean> {
    try {
      const record = await this.getConsentRecord(token);
      if (!record) {return false;}

      record.revoked = true;
      record.revokedDate = new Date().toISOString();
      await this.storeConsentRecord(token, record);

      // Clear all data for this child (consent record is already marked
      // revoked above and intentionally kept for the audit trail)
      await this.clearChildData();

      return true;
    } catch (error) {
      logger.error('Error revoking consent:', error);
      return false;
    }
  }

  /**
   * Check if user has valid parental consent
   */
  async hasValidConsent(consentToken?: string): Promise<boolean> {
    if (!consentToken) {
      // Check if there's a stored consent token
      consentToken = sessionStorage.getItem('coppa_consent_token') || '';
    }

    if (!consentToken) {return false;}

    const record = await this.getConsentRecord(consentToken);
    return record?.verified === true && record?.revoked !== true;
  }

  /**
   * Enable zero-data mode (for under-13s without consent)
   */
  enableZeroDataMode(): void {
    sessionStorage.setItem(COPPAComplianceManager.ZERO_DATA_FLAG, 'true');
    
    // Disable analytics
    if (typeof window !== 'undefined') {
      (window as any).ga?.('set', 'anonymizeIp', true);
      (window as any).ga?.('set', 'allowAdFeatures', false);
    }
  }

  /**
   * Disable zero-data mode
   */
  disableZeroDataMode(): void {
    sessionStorage.removeItem(COPPAComplianceManager.ZERO_DATA_FLAG);
  }

  /**
   * Check if zero-data mode is enabled
   */
  isZeroDataMode(): boolean {
    return sessionStorage.getItem(COPPAComplianceManager.ZERO_DATA_FLAG) === 'true';
  }

  /**
   * Clear user activity data when consent is revoked.
   *
   * The consent-record store (CONSENT_STORAGE_KEY) is intentionally preserved
   * as an audit trail.  This allows subsequent calls to verifyConsentToken to
   * correctly return "This consent has been revoked" rather than the misleading
   * "Invalid consent token" that would be returned if the record were deleted.
   */
  private clearChildData(): void {
    try {
      // Remove all user activity/progress data but leave the consent store intact.
      const keys = Object.keys(localStorage);
      keys.forEach(key => {
        // CONSENT_STORAGE_KEY is intentionally excluded: the revoked record
        // must remain in the store so that verifyConsentToken can return
        // "This consent has been revoked" rather than "Invalid consent token".
        if (key.startsWith('pandagarde_') && key !== COPPAComplianceManager.CONSENT_STORAGE_KEY) {
          localStorage.removeItem(key);
        }
      });

      // Clear sessionStorage (zero-data flag, session consent token, etc.).
      sessionStorage.clear();
    } catch (error) {
      logger.error('Error clearing child data:', error);
    }
  }

  /**
   * Get current user ID
   */
  private getCurrentUserId(): string {
    let userId = localStorage.getItem('pandagarde_user_id');
    if (!userId) {
      userId = `user_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      localStorage.setItem('pandagarde_user_id', userId);
    }
    return userId;
  }

  /**
   * Validate email address
   */
  private isValidEmail(email: string): boolean {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }

  /**
   * Get all consent records for a parent email
   */
  async getConsentsByEmail(parentEmail: string): Promise<ParentalConsentRecord[]> {
    const allConsents = await this.getAllConsentRecords();
    return Object.values(allConsents).filter(
      record => record.parentEmail.toLowerCase() === parentEmail.toLowerCase()
    );
  }
}

// Export singleton instance
export const coppaComplianceManager = new COPPAComplianceManager();

import { logger } from './logger';

interface ServiceWorkerConfig {
  enabled: boolean;
  updateInterval: number;
  cacheStrategy: 'aggressive' | 'conservative';
}

class ServiceWorkerManager {
  private config: ServiceWorkerConfig;
  private registration: ServiceWorkerRegistration | null = null;
  private updateCheckInterval: number | null = null;

  constructor(config: ServiceWorkerConfig) {
    this.config = config;
  }

  // Register service worker
  async register(): Promise<ServiceWorkerRegistration | null> {
    if (!this.config.enabled || !('serviceWorker' in navigator)) {
      logger.debug('Service Worker not supported or disabled', undefined, 'SW');
      return null;
    }

    try {
      this.registration = await navigator.serviceWorker.register('/sw.js', {
        scope: '/',
      });

      logger.debug('Service Worker registered', undefined, 'SW');

      // Handle updates
      this.registration.addEventListener('updatefound', () => {
        this.handleUpdate();
      });

      // Start periodic update checks
      this.startUpdateChecks();

      return this.registration;
    } catch (error) {
      logger.error('Service Worker registration failed:', error);
      return null;
    }
  }

  // Handle service worker updates
  private handleUpdate() {
    if (!this.registration) {return;}

    const newWorker = this.registration.installing;
    if (!newWorker) {return;}

    newWorker.addEventListener('statechange', () => {
      if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
        // New service worker is available
        this.showUpdateConfirmation();
      }
    });
  }

  // Show update notification to user
  private showUpdateConfirmation() {
    const shouldUpdate = confirm(
      'A new version of Privacy Panda is available. Would you like to update now?'
    );

    if (shouldUpdate) {
      this.updateServiceWorker();
    }
  }

  // Update service worker
  private async updateServiceWorker() {
    if (!this.registration) {return;}

    try {
      const newWorker = this.registration.waiting;
      if (newWorker) {
        newWorker.postMessage({ type: 'SKIP_WAITING' });
        
        // Reload page after update
        window.location.reload();
      }
    } catch (error) {
      logger.error('Service Worker update failed:', error);
    }
  }

  // Start periodic update checks
  private startUpdateChecks() {
    if (this.updateCheckInterval) {
      clearInterval(this.updateCheckInterval);
    }

    this.updateCheckInterval = window.setInterval(() => {
      this.checkForUpdates();
    }, this.config.updateInterval);
  }

  // Check for service worker updates
  private async checkForUpdates() {
    if (!this.registration) {return;}

    try {
      await this.registration.update();
    } catch (error) {
      logger.error('Update check failed:', error);
    }
  }

  // Unregister service worker
  async unregister(): Promise<boolean> {
    if (!this.registration) {return false;}

    try {
      const result = await this.registration.unregister();
      
      if (this.updateCheckInterval) {
        clearInterval(this.updateCheckInterval);
        this.updateCheckInterval = null;
      }

      logger.debug('Service Worker unregistered', undefined, 'SW');
      return result;
    } catch (error) {
      logger.error('Service Worker unregistration failed:', error);
      return false;
    }
  }

  // Clear all caches
  async clearCaches(): Promise<void> {
    try {
      const cacheNames = await caches.keys();
      await Promise.all(
        cacheNames.map(cacheName => caches.delete(cacheName))
      );
      logger.debug('All caches cleared', undefined, 'SW');
    } catch (error) {
      logger.error('Cache clearing failed:', error);
    }
  }

  // Get cache storage info
  async getCacheInfo(): Promise<{ name: string; size: number }[]> {
    try {
      const cacheNames = await caches.keys();
      const cacheInfo = await Promise.all(
        cacheNames.map(async (name) => {
          const cache = await caches.open(name);
          const keys = await cache.keys();
          const size = keys.reduce((total, request) => {
            return total + (request.url.length * 2); // Rough estimate
          }, 0);
          
          return { name, size };
        })
      );
      
      return cacheInfo;
    } catch (error) {
      logger.error('Cache info retrieval failed:', error);
      return [];
    }
  }

  // Request background sync
  async requestBackgroundSync(tag: string): Promise<void> {
    if (!this.registration) {return;}

    try {
      await this.registration.sync.register(tag);
      logger.debug('Background sync registered', tag, 'SW');
    } catch (error) {
      logger.error('Background sync registration failed:', error);
    }
  }

  // Cache tool assets for offline use
  async cacheToolAssets(toolId: string): Promise<void> {
    try {
      await this.sendMessage({
        type: 'CACHE_TOOL_ASSETS',
        toolId
      });
      logger.debug(`Tool assets cached for: ${toolId}`, undefined, 'SW');
    } catch (error) {
      logger.error('Tool asset caching failed:', error);
    }
  }

  // Cache mission content for offline use
  async cacheMissionContent(missionId: string): Promise<void> {
    try {
      await this.sendMessage({
        type: 'CACHE_MISSION_CONTENT',
        missionId
      });
      logger.debug(`Mission content cached for: ${missionId}`, undefined, 'SW');
    } catch (error) {
      logger.error('Mission content caching failed:', error);
    }
  }

  // Show update notification
  async showUpdateNotification(message?: string): Promise<void> {
    try {
      await this.sendMessage({
        type: 'SHOW_UPDATE_NOTIFICATION',
        message
      });
    } catch (error) {
      logger.error('Update notification failed:', error);
    }
  }

  // Send message to service worker
  async sendMessage(message: unknown): Promise<unknown> {
    if (!this.registration || !this.registration.active) {
      throw new Error('No active service worker');
    }

    return new Promise((resolve, reject) => {
      const messageChannel = new MessageChannel();
      
      messageChannel.port1.onmessage = (event) => {
        resolve(event.data);
      };

      this.registration!.active!.postMessage(message, [messageChannel.port2]);
      
      // Timeout after 5 seconds
      setTimeout(() => {
        reject(new Error('Message timeout'));
      }, 5000);
    });
  }

  // Check if service worker is supported
  static isSupported(): boolean {
    return 'serviceWorker' in navigator;
  }

  // Check if app is running in PWA mode
  static isPWA(): boolean {
    return window.matchMedia('(display-mode: standalone)').matches ||
           (window.navigator as unknown as { standalone?: boolean }).standalone === true;
  }

  // Get service worker status
  getStatus(): 'registered' | 'unregistered' | 'error' | 'unsupported' {
    if (!ServiceWorkerManager.isSupported()) {
      return 'unsupported';
    }
    
    if (this.registration) {
      return 'registered';
    }
    
    return 'unregistered';
  }
}

// Default configuration
// DISABLED in development to prevent cache issues
const defaultConfig: ServiceWorkerConfig = {
  enabled: import.meta.env.MODE === 'production' && import.meta.env.VITE_SW_ENABLED !== 'false',
  updateInterval: 24 * 60 * 60 * 1000, // 24 hours
  cacheStrategy: 'conservative',
};

// Create singleton instance
export const serviceWorkerManager = new ServiceWorkerManager(defaultConfig);

// Initialize service worker
export const initServiceWorker = async (): Promise<void> => {
  try {
    await serviceWorkerManager.register();
  } catch (error) {
    logger.error('Service Worker initialization failed:', error);
  }
};

// Utility functions
export const clearAllCaches = () => serviceWorkerManager.clearCaches();
export const getCacheInfo = () => serviceWorkerManager.getCacheInfo();
export const requestBackgroundSync = (tag: string) => serviceWorkerManager.requestBackgroundSync(tag);
export const sendMessageToSW = (message: unknown) => serviceWorkerManager.sendMessage(message);
export const cacheToolAssets = (toolId: string) => serviceWorkerManager.cacheToolAssets(toolId);
export const cacheMissionContent = (missionId: string) => serviceWorkerManager.cacheMissionContent(missionId);
export const showUpdateNotification = (message?: string) => serviceWorkerManager.showUpdateNotification(message);

// Export types
export type { ServiceWorkerConfig };
export { ServiceWorkerManager };

